class Solution {
    public int findBestValue(int[] arr, int target) {
        int left = 0, right = (int) 1e5;
        while (left < right) {
            int mid = left + (right - left) / 2;
            int sum = 0;
            for (int num : arr) {
                sum += Math.min(num, mid);
            }
            if (sum < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        int res = left;
        int sum1 = 0;
        for (int num : arr) {
            sum1 += Math.min(num, res);
        }
        int sum2 = 0;
        for (int num : arr) {
            sum2 += Math.min(num, res - 1);
        }
        return Math.abs(sum1 - target) <= Math.abs(sum2 - target) ? res : res - 1;
    }
}
